class PathFinder {
    def graph; // Adjacency list representation of the graph
    PathFinder(Map<Integer, List<Integer>> adjList) {
        this.graph = adjList;
    }

    private boolean isValidNode(int node) {
        return 0 <= node && node < graph.keySet().size();
    }

    public boolean hasPathBetweenNodes(int start, int end) {
        if (!isValidNode(start) || !isValidNode(end)) {
            throw new IllegalArgumentException("Invalid nodes provided.");
        }

        Set<Integer> visited = new HashSet<>();
        return hasPathBetweenNodesUtil(start, end, visited);
    }

    private boolean hasPathBetweenNodesUtil(int node1, int node2, Set<Integer> visited) {
        if (node1 == node2) return true;

        List<Integer> neighbours = graph.getOrDefault(node1, new ArrayList<>());
        for (Integer neighbour : neighbours) {
            if (!visited.contains(neighbour)) {
                visited.add(neighbour);

                if (hasPathBetweenNodesUtil(neighbour, node2, visited)) {
                    return true;
                }
            }
        }

        return false;
    }
}

